"""A shopping cart with line items and pluggable discount strategies.

Monetary amounts use :class:`decimal.Decimal` to avoid the rounding errors
inherent to binary floating point, which are unacceptable for currency.
"""

from __future__ import annotations

from abc import ABC, abstractmethod
from dataclasses import dataclass, field, replace
from decimal import ROUND_HALF_UP, Decimal
from typing import Iterable, Mapping


class ShoppingCartError(Exception):
    """Base class for all shopping cart errors."""


class ItemNotFoundError(ShoppingCartError):
    """Raised when an operation references a product not present in the cart."""

    def __init__(self, product_name: str) -> None:
        super().__init__(f"No item named {product_name!r} exists in the cart.")
        self.product_name = product_name


class DuplicateItemError(ShoppingCartError):
    """Raised when adding a product that is already in the cart."""

    def __init__(self, product_name: str) -> None:
        super().__init__(
            f"Item {product_name!r} is already in the cart; "
            "update its quantity instead."
        )
        self.product_name = product_name


class InvalidPriceError(ShoppingCartError):
    """Raised when a unit price is zero or negative."""

    def __init__(self, unit_price: Decimal) -> None:
        super().__init__(f"Unit price must be greater than zero, got {unit_price}.")
        self.unit_price = unit_price


class InvalidQuantityError(ShoppingCartError):
    """Raised when a quantity is not a positive integer."""

    def __init__(self, quantity: int) -> None:
        super().__init__(f"Quantity must be a positive integer, got {quantity}.")
        self.quantity = quantity


class InvalidDiscountError(ShoppingCartError):
    """Raised when a discount is configured with an out-of-range value."""


_CURRENCY_PRECISION = Decimal("0.01")


def _to_money(amount: Decimal | int | str) -> Decimal:
    """Normalize a value to a currency-precision :class:`Decimal`."""
    return Decimal(amount).quantize(_CURRENCY_PRECISION, rounding=ROUND_HALF_UP)


@dataclass(frozen=True)
class CartItem:
    """An immutable line item: a product, its unit price, and a quantity."""

    product_name: str
    unit_price: Decimal
    quantity: int

    @property
    def line_total(self) -> Decimal:
        """Total cost for this line (unit price multiplied by quantity)."""
        return _to_money(self.unit_price * self.quantity)


class DiscountStrategy(ABC):
    """Computes the amount to subtract from a subtotal."""

    @abstractmethod
    def discount_amount(self, subtotal: Decimal) -> Decimal:
        """Return the absolute discount applied to ``subtotal``."""


@dataclass(frozen=True)
class PercentageDiscount(DiscountStrategy):
    """A discount expressed as a percentage of the subtotal (0–100)."""

    percentage: Decimal

    def __post_init__(self) -> None:
        if not Decimal(0) <= self.percentage <= Decimal(100):
            raise InvalidDiscountError(
                f"Percentage must be between 0 and 100, got {self.percentage}."
            )

    def discount_amount(self, subtotal: Decimal) -> Decimal:
        return _to_money(subtotal * self.percentage / Decimal(100))


@dataclass(frozen=True)
class FlatDiscount(DiscountStrategy):
    """A fixed-amount discount, capped at the subtotal so totals never go negative."""

    amount: Decimal

    def __post_init__(self) -> None:
        if self.amount < Decimal(0):
            raise InvalidDiscountError(
                f"Flat discount cannot be negative, got {self.amount}."
            )

    def discount_amount(self, subtotal: Decimal) -> Decimal:
        return _to_money(min(self.amount, subtotal))


@dataclass
class ShoppingCart:
    """A collection of unique line items with an optional discount.

    Items are keyed by product name, so each product appears at most once;
    use :meth:`update_quantity` to change how many of a product are in the cart.
    """

    _items: dict[str, CartItem] = field(default_factory=dict)
    _discount: DiscountStrategy | None = None

    def add_item(
        self, product_name: str, unit_price: Decimal | int | str, quantity: int
    ) -> CartItem:
        """Add a new product to the cart and return the created line item.

        Raises:
            DuplicateItemError: If the product is already in the cart.
            InvalidPriceError: If ``unit_price`` is not positive.
            InvalidQuantityError: If ``quantity`` is not a positive integer.
        """
        if product_name in self._items:
            raise DuplicateItemError(product_name)
        price = self._validate_price(unit_price)
        self._validate_quantity(quantity)
        item = CartItem(product_name, price, quantity)
        self._items[product_name] = item
        return item

    def remove_item(self, product_name: str) -> None:
        """Remove a product from the cart.

        Raises:
            ItemNotFoundError: If the product is not in the cart.
        """
        if self._items.pop(product_name, None) is None:
            raise ItemNotFoundError(product_name)

    def update_quantity(self, product_name: str, quantity: int) -> CartItem:
        """Set the quantity of an existing product and return the updated item.

        Raises:
            ItemNotFoundError: If the product is not in the cart.
            InvalidQuantityError: If ``quantity`` is not a positive integer.
        """
        existing_item = self._require_item(product_name)
        self._validate_quantity(quantity)
        updated_item = replace(existing_item, quantity=quantity)
        self._items[product_name] = updated_item
        return updated_item

    def apply_discount(self, discount: DiscountStrategy) -> None:
        """Attach a discount strategy to be applied when computing the total."""
        self._discount = discount

    def clear_discount(self) -> None:
        """Remove any previously applied discount."""
        self._discount = None

    def clear(self) -> None:
        """Remove all items and any applied discount from the cart."""
        self._items.clear()
        self._discount = None

    @property
    def subtotal(self) -> Decimal:
        """The combined line total of all items, before any discount."""
        return _to_money(
            sum((item.line_total for item in self._items.values()), Decimal(0))
        )

    @property
    def discount_amount(self) -> Decimal:
        """The absolute discount applied to the subtotal (zero if none set)."""
        if self._discount is None:
            return _to_money(Decimal(0))
        return self._discount.discount_amount(self.subtotal)

    @property
    def total(self) -> Decimal:
        """The amount payable after applying the discount to the subtotal."""
        return _to_money(self.subtotal - self.discount_amount)

    def list_items(self) -> tuple[CartItem, ...]:
        """Return all line items as an immutable, insertion-ordered tuple."""
        return tuple(self._items.values())

    def __len__(self) -> int:
        """The number of distinct products in the cart."""
        return len(self._items)

    def __contains__(self, product_name: object) -> bool:
        """Whether a product name is present in the cart."""
        return product_name in self._items

    def _require_item(self, product_name: str) -> CartItem:
        """Return an existing item or raise :class:`ItemNotFoundError`."""
        try:
            return self._items[product_name]
        except KeyError:
            raise ItemNotFoundError(product_name) from None

    @staticmethod
    def _validate_price(unit_price: Decimal | int | str) -> Decimal:
        """Normalize and validate a unit price, returning currency-precision money."""
        price = _to_money(unit_price)
        if price <= Decimal(0):
            raise InvalidPriceError(price)
        return price

    @staticmethod
    def _validate_quantity(quantity: int) -> None:
        """Validate that a quantity is a positive integer."""
        if not isinstance(quantity, int) or isinstance(quantity, bool) or quantity <= 0:
            raise InvalidQuantityError(quantity)

    @classmethod
    def from_items(cls, items: Iterable[Mapping[str, object]]) -> ShoppingCart:
        """Build a cart from an iterable of mappings with product/price/quantity keys."""
        cart = cls()
        for item in items:
            cart.add_item(
                product_name=str(item["product_name"]),
                unit_price=item["unit_price"],  # type: ignore[arg-type]
                quantity=int(item["quantity"]),  # type: ignore[call-overload]
            )
        return cart
