    def add_item(self, product_name: str, unit_price: MoneyInput, quantity: int) -> None:
        """Add an item to the cart or increase its quantity if it already exists."""
        normalized_name = self._validate_product_name(product_name)
        validated_price = self._validate_money(unit_price, field_name="unit price")
        validated_quantity = self._validate_positive_quantity(quantity)

